/* ══════════════════════════════════════════
   SHARED — Footer & Nav data
══════════════════════════════════════════ */
function renderSharedData() {
  const R = RESUME;
  // Footer email/linkedin links
  qsa('[data-email]').forEach(a => { a.href = `mailto:${R.contact.email}`; a.textContent = a.dataset.emailLabel || 'Email'; });
  qsa('[data-linkedin]').forEach(a => { a.href = R.contact.linkedinUrl; });
  qsa('[data-github]').forEach(a => { a.href = R.contact.githubUrl; });
  // Copyright year
  qsa('.year').forEach(e => e.textContent = new Date().getFullYear());
  // Page <title> suffix
  const titleEl = document.querySelector('title');
  if (titleEl && !titleEl.dataset.custom) {
    titleEl.textContent = titleEl.textContent.replace('__NAME__', R.name.display);
  }
}

/* ── Run all renderers ── */
document.addEventListener('DOMContentLoaded', () => {
  renderSharedData();
  renderIndex();
  renderAbout();
  renderExperience();
  renderProjects();
  renderSkills();
  renderContact();
});
